    <div class="cp-loading-row"><div class="skeleton" style="width:100%;height:40px"></div></div>
    <div class="cp-loading-row"><div class="skeleton" style="width:100%;height:40px"></div></div>
    <div class="cp-loading-row"><div class="skeleton" style="width:100%;height:40px"></div></div>
  </div>`;

